import json
import time
import sys
from playwright.sync_api import sync_playwright

def main():
    with sync_playwright() as p:
        browser = p.chromium.launch(headless=True)
        page = browser.new_page()

        # Navigate to CSRankings with specific hash pre-selected to avoid timeout logic 
        # on JS generated options. We know the hash format:
        # #/index?ai&vision&mlmining&nlp&inforet&world
        # But we still need to set years, and it seems years options are loaded via JS.
        # So we wait for networkidle or use a slightly longer timeout.
        try:
            page.goto('https://csrankings.org/#/index?ai&vision&mlmining&nlp&inforet&world', timeout=60000, wait_until='networkidle')
        except Exception:
            pass

        # We need to ensure that the table is loaded
        try:
            page.wait_for_selector('#ranking tbody tr', timeout=30000)
        except Exception:
            print(json.dumps({"error": "Failed to load rankings table"}))
            browser.close()
            return

        # Since options for 'fromyear' and 'toyear' are populated dynamically, 
        # let's wait until they have the options.
        try:
            page.wait_for_function('document.querySelector("#fromyear").options.length > 0', timeout=30000)
        except Exception:
            pass

        # Set years
        page.evaluate('''() => {
            let fy = document.querySelector('#fromyear');
            if(fy && fy.value !== '2020') { fy.value = '2020'; fy.dispatchEvent(new Event('change')); }

            let ty = document.querySelector('#toyear');
            if(ty && ty.value !== '2025') { ty.value = '2025'; ty.dispatchEvent(new Event('change')); }
        }''')

        # We might need a bit of time for the table to reload after changing years
        time.sleep(3)

        # Wait for the table row that contains SJTU
        res = page.evaluate('''() => {
            let trs = Array.from(document.querySelectorAll('#ranking tbody tr'));
            let target = trs.find(tr => tr.innerText.includes("Shanghai Jiao Tong"));
            if (!target) return null;
            let tds = target.querySelectorAll('td');
            return {
                rank: tds[0].innerText.trim(),
                count: tds[2].innerText.trim(),
                faculty: tds[3].innerText.trim()
            };
        }''')

        if res:
            # We must output exact JSON to stdout
            output = {
                "final_url": page.url,
                "data": {
                    "institution": "Shanghai Jiao Tong University",
                    "rank": int(res["rank"]),
                    "count": float(res["count"]),
                    "faculty": int(res["faculty"])
                }
            }
            print(json.dumps(output, indent=2))
        else:
            # fallback if not found
            print(json.dumps({"error": "Shanghai Jiao Tong University not found in the filtered list."}))

        browser.close()

if __name__ == '__main__':
    main()
