        except Exception:
            pass

        # We need to ensure that the table is loaded
        try:
            page.wait_for_selector('#ranking tbody tr', timeout=30000)
        except Exception:
            print(json.dumps({"error": "Failed to load rankings table"}))
            browser.close()
            return

        # Since options for 'fromyear' and 'toyear' are populated dynamically, 
        # let's wait until they have the options.
        try:
            page.wait_for_function('document.querySelector("#fromyear").options.length > 0', timeout=30000)
        except Exception:
            pass

        # Set years
        page.evaluate('''() => {
            let fy = document.querySelector('#fromyear');
            if(fy && fy.value !== '2020') { fy.value = '2020'; fy.dispatchEvent(new Event('change')); }

            let ty = document.querySelector('#toyear');
            if(ty && ty.value !== '2025') { ty.value = '2025'; ty.dispatchEvent(new Event('change')); }
        }''')

