            let target = trs.find(tr => tr.innerText.includes("Shanghai Jiao Tong"));
            if (!target) return null;
            let tds = target.querySelectorAll('td');
            return {
                rank: tds[0].innerText.trim(),
                count: tds[2].innerText.trim(),
                faculty: tds[3].innerText.trim()
            };
        }''')

        if res:
            # We must output exact JSON to stdout
